solution: ```class Solution {
public:
    int minimumOperationsToMakeEqual(int x, int y) {
        if (x == y) return 0;
        const int INF = 1e9;
        vector<int> dist(10001, INF);
        queue<int> q;
        dist[x] = 0;
        q.push(x);
        while (!q.empty()) {
            int cur = q.front(); q.pop();
            if (cur == y) return dist[cur];
            vector<int> nexts;
            nexts.push_back(cur - 1);
            nexts.push_back(cur + 1);
            if (cur % 11 == 0) nexts.push_back(cur / 11);
            if (cur % 5 == 0) nexts.push_back(cur / 5);
            for (int nxt : nexts) {
                if (nxt < 1 || nxt > 10000) continue;
                if (dist[nxt] == INF) {
                    dist[nxt] = dist[cur] + 1;
                    q.push(nxt);
                }
            }
        }
        return dist[y];
    }
};
